import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const BLOOD_GROUPS = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'];

const api = axios.create({ baseURL: '/api' });

export default function DonorRegister() {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    name: '', email: '', phone: '', bloodGroup: '',
    location: '', lastDonationDate: '', isAvailable: true,
  });
  const [saving, setSaving] = useState(false);
  const [err, setErr] = useState('');
  const [success, setSuccess] = useState(false);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const submit = async (e) => {
    e.preventDefault();
    setSaving(true); setErr('');
    try {
      const payload = { ...form };
      if (!payload.lastDonationDate) delete payload.lastDonationDate;
      await api.post('/blood/donors/public', payload);
      setSuccess(true);
    } catch (ex) {
      setErr(ex.response?.data?.message || 'Registration failed. Please try again.');
    } finally { setSaving(false); }
  };

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #0f2d55 0%, #1a4a7a 50%, #1a5c6e 100%)', display: 'flex', flexDirection: 'column' }}>
      {/* Navbar */}
      <nav style={{ padding: '1rem 2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
        <button onClick={() => navigate('/')} style={{ background: 'none', border: 'none', color: '#fff', display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', fontSize: '1rem' }}>
          <i className="bi bi-arrow-left" />
          <span style={{ fontWeight: 700 }}>MediCare EHR</span>
        </button>
        <button className="btn btn-outline-light btn-sm" onClick={() => navigate('/login')}>Login</button>
      </nav>

      <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '2rem 1rem' }}>
        <div style={{ background: '#fff', borderRadius: 16, padding: '2rem', width: '100%', maxWidth: 560, boxShadow: '0 20px 60px rgba(0,0,0,0.3)' }}>

          {success ? (
            <div style={{ textAlign: 'center', padding: '2rem 0' }}>
              <div style={{ width: 72, height: 72, borderRadius: '50%', background: '#dcfce7', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 1rem' }}>
                <i className="bi bi-check-circle-fill" style={{ fontSize: '2rem', color: '#16a34a' }} />
              </div>
              <h4 style={{ color: '#1F2937', marginBottom: 8 }}>Registration Successful!</h4>
              <p style={{ color: '#6B7280', marginBottom: '1.5rem' }}>Thank you for registering as a blood donor. Your contribution can save lives.</p>
              <div style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' }}>
                <button className="btn btn-primary" onClick={() => navigate('/')}>Back to Home</button>
                <button className="btn btn-outline-secondary" onClick={() => { setSuccess(false); setForm({ name: '', email: '', phone: '', bloodGroup: '', location: '', lastDonationDate: '', isAvailable: true }); }}>
                  Register Another
                </button>
              </div>
            </div>
          ) : (
            <>
              <div style={{ textAlign: 'center', marginBottom: '1.5rem' }}>
                <div style={{ width: 56, height: 56, borderRadius: '50%', background: '#fff0f0', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 0.75rem', border: '2px solid #fecaca' }}>
                  <i className="bi bi-person-heart" style={{ fontSize: '1.5rem', color: '#ef4444' }} />
                </div>
                <h4 style={{ color: '#1F2937', marginBottom: 4 }}>Become a Blood Donor</h4>
                <p style={{ color: '#6B7280', fontSize: '0.875rem', margin: 0 }}>Fill in your details to register as a donor</p>
              </div>

              {err && <div className="alert alert-danger py-2 mb-3" style={{ fontSize: '0.875rem' }}>{err}</div>}

              <form onSubmit={submit}>
                <div className="row g-3">
                  <div className="col-6">
                    <label className="form-label" style={{ fontSize: '0.875rem', fontWeight: 600 }}>Full Name *</label>
                    <input className="form-control" required value={form.name} onChange={e => set('name', e.target.value)} placeholder="Your full name" />
                  </div>
                  <div className="col-6">
                    <label className="form-label" style={{ fontSize: '0.875rem', fontWeight: 600 }}>Phone *</label>
                    <input className="form-control" required value={form.phone} onChange={e => set('phone', e.target.value)} placeholder="+91 XXXXX XXXXX" />
                  </div>
                  <div className="col-6">
                    <label className="form-label" style={{ fontSize: '0.875rem', fontWeight: 600 }}>Email</label>
                    <input type="email" className="form-control" value={form.email} onChange={e => set('email', e.target.value)} placeholder="optional" />
                  </div>
                  <div className="col-6">
                    <label className="form-label" style={{ fontSize: '0.875rem', fontWeight: 600 }}>Blood Group *</label>
                    <select className="form-select" required value={form.bloodGroup} onChange={e => set('bloodGroup', e.target.value)}>
                      <option value="">Select</option>
                      {BLOOD_GROUPS.map(g => <option key={g}>{g}</option>)}
                    </select>
                  </div>
                  <div className="col-12">
                    <label className="form-label" style={{ fontSize: '0.875rem', fontWeight: 600 }}>City / Location *</label>
                    <input className="form-control" required value={form.location} onChange={e => set('location', e.target.value)} placeholder="e.g. Mumbai, Maharashtra" />
                  </div>
                  <div className="col-12">
                    <label className="form-label" style={{ fontSize: '0.875rem', fontWeight: 600 }}>Last Donation Date</label>
                    <input type="date" className="form-control" value={form.lastDonationDate} onChange={e => set('lastDonationDate', e.target.value)} />
                    <div style={{ fontSize: '0.75rem', color: '#6B7280', marginTop: 3 }}>Leave blank if you haven't donated before</div>
                  </div>
                  <div className="col-12">
                    <div className="form-check">
                      <input className="form-check-input" type="checkbox" id="avail" checked={form.isAvailable} onChange={e => set('isAvailable', e.target.checked)} />
                      <label className="form-check-label" htmlFor="avail" style={{ fontSize: '0.875rem' }}>I am currently available to donate</label>
                    </div>
                  </div>
                  <div className="col-12 mt-1">
                    <button type="submit" className="btn w-100" disabled={saving}
                      style={{ background: '#ef4444', color: '#fff', border: 'none', borderRadius: 10, padding: '0.75rem', fontWeight: 700, fontSize: '1rem' }}>
                      {saving ? <><span className="spinner-border spinner-border-sm me-2" />Registering...</> : <><i className="bi bi-heart-fill me-2" />Register as Donor</>}
                    </button>
                  </div>
                </div>
              </form>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
